import org.assertj.core.api.Assertions.assertThat
import org.junit.Before
import org.junit.Test
import org.junit.runner.RunWith
import org.mockito.Mock
import org.mockito.junit.MockitoJUnitRunner
import org.mockito.kotlin.any
import org.mockito.kotlin.whenever
import org.wordpress.android.R
import org.wordpress.android.util.LocaleManagerWrapper
import org.wordpress.android.util.text.PercentFormatter
import org.wordpress.android.viewmodel.ResourceProvider
import java.math.RoundingMode.HALF_UP
import java.util.Locale

/**
 * Test class to verify that infinite percentages (when previous value is 0)
 * are handled correctly by not showing "(∞)" but only showing the increase.
 */
@RunWith(MockitoJUnitRunner::class)
class StatsUtilsInfinityPercentageTest {
    @Mock
    lateinit var resourceProvider: ResourceProvider

    @Mock
    lateinit var localeManagerWrapper: LocaleManagerWrapper

    @Mock
    private lateinit var percentFormatter: PercentFormatter
    private lateinit var statsUtils: StatsUtils

    @Before
    fun setUp() {
        statsUtils = StatsUtils(resourceProvider, localeManagerWrapper, percentFormatter)
        whenever(localeManagerWrapper.getLocale()).thenReturn(Locale.US)
        whenever(resourceProvider.getString(any(), any())).then {
            val resourceId = it.getArgument<Int>(0)
            val value = it.getArgument<String>(1)
            when (resourceId) {
                R.string.negative_prefix -> "-$value"
                else -> value
            }
        }
        whenever(resourceProvider.getString(any(), any(), any())).then {
            val resourceId = it.getArgument<Int>(0)
            val value1 = it.getArgument<String>(1)
            val value2 = it.getArgument<String>(2)
            when (resourceId) {
                R.string.stats_traffic_increase -> "+$value1 ($value2)"
                R.string.stats_traffic_change -> "$value1 ($value2)"
                else -> "$value1 $value2"
            }
        }
        whenever(percentFormatter.format(any(), any())).then {
            val value = it.getArgument<Float>(0)
            String.format("%.0f%%", value * 100)
        }
    }

    @Test
    fun `buildChange should not show infinity symbol when previousValue is 0 and positive`() {
        val previousValue = 0L
        val value = 5L
        val positive = true
        val isFormattedNumber = false

        val result = statsUtils.buildChange(previousValue, value, positive, isFormattedNumber)

        // Should return "+5" without "(∞)"
        assertThat(result).isEqualTo("+5")
    }

    @Test
    fun `buildChange should not show infinity symbol when previousValue is 0 and not positive`() {
        val previousValue = 0L
        val value = 5L
        val positive = false
        val isFormattedNumber = false

        val result = statsUtils.buildChange(previousValue, value, positive, isFormattedNumber)

        // Should return "5" without "(∞)"
        assertThat(result).isEqualTo("5")
    }

    @Test
    fun `buildChange should show percentage when previousValue is not 0`() {
        val previousValue = 10L
        val value = 15L
        val positive = true
        val isFormattedNumber = false

        val result = statsUtils.buildChange(previousValue, value, positive, isFormattedNumber)

        // Should return "+5 (50%)" with the percentage
        assertThat(result).isEqualTo("+5 (50%)")
    }

    @Test
    fun `buildChange should show 0 percentage when value equals previousValue`() {
        val previousValue = 10L
        val value = 10L
        val positive = true
        val isFormattedNumber = false

        val result = statsUtils.buildChange(previousValue, value, positive, isFormattedNumber)

        // Should return "+0 (0)" 
        assertThat(result).isEqualTo("+0 (0)")
    }

    @Test
    fun `buildChange should handle formatted numbers when previousValue is 0`() {
        val previousValue = 0L
        val value = 10000L
        val positive = true
        val isFormattedNumber = true

        // Mock the toFormattedString behavior
        whenever(resourceProvider.getString(any(), any())).then {
            val resourceId = it.getArgument<Int>(0)
            val value = it.getArgument<String>(1)
            when (resourceId) {
                R.string.suffix_1_000 -> value + "k"
                else -> value
            }
        }

        val result = statsUtils.buildChange(previousValue, value, positive, isFormattedNumber)

        // Should return "+10k" without "(∞)"
        assertThat(result).isEqualTo("+10k")
    }
}
"}

