import kotlinx.coroutines.ExperimentalCoroutinesApi
import org.assertj.core.api.Assertions.assertThat
import org.junit.Before
import org.junit.Test
import org.mockito.Mock
import org.mockito.kotlin.any
import org.mockito.kotlin.whenever
import org.wordpress.android.BaseUnitTest
import org.wordpress.android.R
import org.wordpress.android.fluxc.model.stats.PostDetailStatsModel
import org.wordpress.android.ui.stats.refresh.lists.sections.BlockListItem.ValueItem.State
import org.wordpress.android.ui.stats.refresh.utils.StatsDateFormatter
import org.wordpress.android.ui.stats.refresh.utils.StatsUtils
import org.wordpress.android.util.text.PercentFormatter
import org.wordpress.android.viewmodel.ResourceProvider
import java.math.RoundingMode.HALF_UP

/**
 * Test class to verify that infinite percentages (when previous value is 0)
 * are handled correctly in PostDayViewsMapper by not showing "(∞)" but only showing the increase.
 */
@ExperimentalCoroutinesApi
class PostDayViewsMapperInfinityPercentageTest : BaseUnitTest() {
    @Mock
    lateinit var statsDateFormatter: StatsDateFormatter

    @Mock
    lateinit var resourceProvider: ResourceProvider

    @Mock
    lateinit var statsUtils: StatsUtils

    @Mock
    private lateinit var percentFormatter: PercentFormatter
    private lateinit var mapper: PostDayViewsMapper

    @Before
    fun setUp() {
        mapper = PostDayViewsMapper(resourceProvider, statsUtils, statsDateFormatter, percentFormatter)

        // Setup common mocks
        whenever(resourceProvider.getString(R.string.stats_views)).thenReturn("Views")
        whenever(statsDateFormatter.printDate(any())).thenReturn("01. 01. 2020")
        whenever(statsUtils.toFormattedString(any<Int>(), any())).then {
            it.getArgument<Int>(0).toString()
        }
        whenever(resourceProvider.getString(any(), any())).then {
            val resourceId = it.getArgument<Int>(0)
            val value = it.getArgument<String>(1)
            when (resourceId) {
                R.string.negative_prefix -> "-$value"
                else -> value
            }
        }
        whenever(resourceProvider.getString(any(), any(), any(), any())).thenReturn("Content description")
        whenever(resourceProvider.getString(any(), any(), any(), any(), any())).thenReturn("Content description")
        whenever(percentFormatter.format(any(), any())).then {
            val value = it.getArgument<Float>(0)
            String.format("%.0f%%", value * 100)
        }
    }

    @Test
    fun `buildTitle should not show infinity symbol when previousValue is 0`() {
        val currentDay = PostDetailStatsModel.Day("2020-01-02", 5)
        val previousDay = PostDetailStatsModel.Day("2020-01-01", 0)

        val result = mapper.buildTitle(currentDay, previousDay, isLast = false)

        // The change should be "+5" without "(∞)"
        assertThat(result.change).isEqualTo("+5")
        assertThat(result.state).isEqualTo(State.POSITIVE)
    }

    @Test
    fun `buildTitle should show percentage when previousValue is not 0`() {
        val currentDay = PostDetailStatsModel.Day("2020-01-02", 15)
        val previousDay = PostDetailStatsModel.Day("2020-01-01", 10)

        // Mock the string resource formatting for non-infinity case
        whenever(resourceProvider.getString(any(), any(), any())).then {
            val resourceId = it.getArgument<Int>(0)
            val value1 = it.getArgument<String>(1)
            val value2 = it.getArgument<String>(2)
            when (resourceId) {
                R.string.stats_traffic_increase -> "+$value1 ($value2)"
                R.string.stats_traffic_change -> "$value1 ($value2)"
                else -> "$value1 $value2"
            }
        }

        val result = mapper.buildTitle(currentDay, previousDay, isLast = false)

        // The change should include the percentage: "+5 (50%)"
        assertThat(result.change).isEqualTo("+5 (50%)")
        assertThat(result.state).isEqualTo(State.POSITIVE)
    }

    @Test
    fun `buildTitle should handle negative change when previousValue is 0`() {
        val currentDay = PostDetailStatsModel.Day("2020-01-02", 0)
        val previousDay = PostDetailStatsModel.Day("2020-01-01", 0)

        val result = mapper.buildTitle(currentDay, previousDay, isLast = false)

        // When both are 0, difference is 0, should show "+0 (0)"
        // But let's also mock the case
        whenever(resourceProvider.getString(any(), any(), any())).then {
            val resourceId = it.getArgument<Int>(0)
            val value1 = it.getArgument<String>(1)
            val value2 = it.getArgument<String>(2)
            when (resourceId) {
                R.string.stats_traffic_increase -> "+$value1 ($value2)"
                R.string.stats_traffic_change -> "$value1 ($value2)"
                else -> "$value1 $value2"
            }
        }

        // The result should show "+0 (0)" since values are equal
        assertThat(result.change).isEqualTo("+0 (0)")
    }

    @Test
    fun `buildTitle should handle null previousValue`() {
        val currentDay = PostDetailStatsModel.Day("2020-01-02", 5)

        val result = mapper.buildTitle(currentDay, null, isLast = false)

        // When previousValue is null, change should be null
        assertThat(result.change).isNull()
        assertThat(result.state).isEqualTo(State.POSITIVE)
    }
}
"}

